+        </div>
+    </div>
+}
+else if (_errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @_errorMessage
+        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
+    </div>
+}
+else
+{
+    <!-- Stats Bar -->
+    <div class="stats-bar d-flex flex-wrap gap-3 mb-3">
+        <span class="badge bg-primary rounded-pill">Total: @_allTasks.Count</span>
+        <span class="badge bg-secondary rounded-pill">To Do: @GetColumnTasks("To Do").Count</span>
+        <span class="badge bg-info text-dark rounded-pill">In Progress: @GetColumnTasks("In Progress").Count</span>
+        <span class="badge bg-success rounded-pill">Done: @GetColumnTasks("Done").Count</span>
+        <span class="badge bg-danger rounded-pill">Overdue: @_allTasks.Count(t => t.DueDate < DateTime.Today)</span>
+    </div>
+
+    <!-- Search Bar -->
+    <div class="mb-3" style="max-width: 400px;">
+        <input type="text" class="form-control" placeholder="Search tasks by title..."
+               @bind="_searchText" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban Columns -->
+    <div class="board-container d-flex gap-3">
+        @foreach (var column in _columns)
+        {
+            var tasks = GetFilteredColumnTasks(column);
+            var columnIndex = Array.IndexOf(_columns, column);
+            <div class="kanban-column flex-fill">
+                <div class="column-header d-flex justify-content-between align-items-center p-2 rounded-top">
+                    <h5 class="mb-0">@column</h5>
+                    <span class="badge bg-light text-dark">@tasks.Count</span>
+                </div>
+
+                <div class="column-body p-2">
+                    @foreach (var task in tasks)
+                    {
+                        <div class="task-card card mb-2">
+                            <div class="card-body p-2">
+                                <h6 class="card-title mb-1">@task.Title</h6>
+                                <p class="card-text mb-1 text-muted small">@task.Assignee</p>
+                                <div class="d-flex justify-content-between align-items-center mb-1">
+                                    <span class="badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
+                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                </div>
+                                <div class="d-flex gap-1">
+                                    @if (columnIndex > 0)
+                                    {
+                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                @onclick="() => MoveTaskAsync(task.Id, _columns[columnIndex - 1])"
+                                                disabled="@_isMoving">
+                                            &larr; Move Left
+                                        </button>
+                                    }
+                                    @if (columnIndex < _columns.Length - 1)
+                                    {
+                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                                @onclick="() => MoveTaskAsync(task.Id, _columns[columnIndex + 1])"
+                                                disabled="@_isMoving">
+                                            Move Right &rarr;
+                                        </button>
+                                    }
+                                </div>
+                            </div>
+                        </div>
+                    }
+
+                    @if (_addingToColumn == column)
+                    {
+                        <div class="card mb-2 border-primary">
+                            <div class="card-body p-2">
+                                <input type="text" class="form-control form-control-sm mb-1"
+                                       placeholder="Title" @bind="_newTitle" />
+                                <input type="text" class="form-control form-control-sm mb-1"
+                                       placeholder="Assignee" @bind="_newAssignee" />
+                                <select class="form-select form-select-sm mb-1" @bind="_newPriority">
+                                    <option value="High">High</option>
+                                    <option value="Medium">Medium</option>
+                                    <option value="Low">Low</option>
+                                </select>
+                                <input type="date" class="form-control form-control-sm mb-1"
+                                       @bind="_newDueDate" />
+                                <div class="d-flex gap-1">
+                                    <button class="btn btn-primary btn-sm flex-fill"
+                                            @onclick="SaveNewTaskAsync" disabled="@_isSaving">
+                                        @(_isSaving ? "Saving..." : "Save")
+                                    </button>
+                                    <button class="btn btn-outline-secondary btn-sm flex-fill"
+                                            @onclick="CancelAdd" disabled="@_isSaving">
+                                        Cancel
+                                    </button>
+                                </div>
+                            </div>
+                        </div>
+                    }
+                    else
+                    {
+                        <button class="btn btn-outline-primary btn-sm w-100"
+                                @onclick="() => StartAdd(column)">
+                            + Add Task
+                        </button>
+                    }
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> _allTasks = [];
+    private bool _loading = true;
+    private string? _errorMessage;
+    private string _searchText = string.Empty;
+    private bool _isMoving;
+
+    // Add-task form state
+    private string? _addingToColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+    private bool _isSaving;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        _loading = true;
+        _errorMessage = null;
+        try
+        {
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumnTasks(string status) =>
+        _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status)
+    {
+        var tasks = GetColumnTasks(status);
+        if (!string.IsNullOrWhiteSpace(_searchText))
+        {
+            tasks = tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();
+        }
+        return tasks;
+    }
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        _isMoving = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var task = _allTasks.First(t => t.Id == taskId);
+            _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _isMoving = false;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        _addingToColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => _addingToColumn = null;
+
+    private async Task SaveNewTaskAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null)
+            return;
+
+        _isSaving = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
+            // If the task was created with a different status than the target column, update it
+            if (created.Status != _addingToColumn)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
+                created = created with { Status = _addingToColumn };
+            }
+            _allTasks.Add(created);
+            _addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _isSaving = false;
+        }
+    }
+}
+

